listData:
{{(() => {
     const history = GetTrackingHistory.data || [];
     const orderData = GetOrderTracking.data[0] || {};

     // If we have tracking history, use it
     if (history.length > 0) {
       return history.map(event => ({
         status: event.status,
         details: event.details,
         date: moment(event.created_at).format('MMM DD, HH:mm'),
         completed: event.complete,
         icon: event.complete ? "✅" : "⭕"
       }));
     }

     // Otherwise, build from order status
     const timeline = [];

     // Order created
     timeline.push({
       status: "Order Created",
       details: "Order has been placed",
       date: moment(orderData.created_at).format('MMM DD, HH:mm'),
       completed: true,
       icon: "✅"
     });

     // Order dispatched
     if (orderData.dispatched_at) {
       timeline.push({
         status: "Order Dispatched",
         details: "Driver assigned",
         date: moment(orderData.dispatched_at).format('MMM DD, HH:mm'),
         completed: true,
         icon: "✅"
       });
     }

     // In transit
     if (orderData.started_at) {
       timeline.push({
         status: "In Transit",
         details: "On the way",
         date: moment(orderData.started_at).format('MMM DD, HH:mm'),
         completed: true,
         icon: "✅"
       });
     }

     // Add future status
     if (orderData.order_status !== 'delivered') {
       timeline.push({
         status: "Delivery",
         details: "Estimated delivery",
         date: orderData.scheduled_at ? moment(orderData.scheduled_at).format('MMM DD, HH:mm') : "Today",
         completed: false,
         icon: "⭕"
       });
     }

     return timeline;
   })()}}
